const ALL_QUESTIONS = [
  // ===== WEEKLY LAWN MAINTENANCE (1-18) =====
  {id:1,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What happens to grass clippings under the Nutrient Standard mowing plan?",options:["They are bagged and removed","They are finely mulched and returned to the lawn","They are composted on-site","The client chooses each visit"],answer:1,explanation:"Nutrient Standard mulches clippings and returns them to the lawn, recycling nutrients."},
  {id:2,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"What is the key upgrade with Pristine Standard mowing over Nutrient Standard?",options:["Twice-weekly mowing","Bagging and removal of all grass clippings","Fertilizer included","Edging of all garden beds"],answer:1,explanation:"Pristine bags and removes all clippings. Everything else is the same."},
  {id:3,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Which is included in BOTH Nutrient Standard and Pristine Standard mowing?",options:["Bagging of clippings","Fertilizer application","String trimming around edges, obstacles, and beds + blowing hard surfaces","Garden bed weeding"],answer:2,explanation:"Both include mowing, string trimming, and blowing."},
  {id:4,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Does Nutrient Standard mowing leave messy piles of grass on the lawn?",options:["Yes — clippings are left in piles","No — clippings are finely mulched so they break down quickly","Only during peak growing season","It depends on the lawn size"],answer:1,explanation:"Clippings are finely mulched, not left in piles."},
  {id:5,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"A client says: \"I don't want grass clippings left on my lawn — it looks messy.\" What's the best response?",options:["Tell them Nutrient Standard doesn't leave clippings at all","Explain that Nutrient mulches finely (barely visible) but Pristine bags everything if a clean look matters most","Tell them to go with Pristine — Nutrient is a mess","Say you can't control where clippings land"],answer:1,explanation:"Explain both tiers honestly — Nutrient mulches finely and isn't messy, but Pristine bags everything for a perfectly clean look."},
  {id:6,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"A client asks: \"Why should I pay more for Pristine mowing?\" What's the best explanation?",options:["Pristine uses better mowing equipment","Pristine bags and removes all clippings for a consistently clean appearance — everything else is the same","Pristine crews are more experienced","Pristine includes fertilizer and weed control"],answer:1,explanation:"Same visit — only difference is clippings are bagged and removed."},
  {id:7,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What does 'Nutrient Standard' mean across Amigos' services?",options:["We apply fertilizer nutrients","Organic material is returned to the soil to recycle nutrients naturally","We use only organic products","It's the premium tier"],answer:1,explanation:"Organic material returned to soil to recycle nutrients naturally."},
  {id:8,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What does 'Pristine Standard' mean across Amigos services?",options:["We use the highest quality materials","All collected material is completely hauled away for a clean appearance","We visit twice as often","Chemical treatments are included"],answer:1,explanation:"All material hauled away for a perfectly clean appearance."},
  {id:9,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"Besides clipping handling, is there ANY other difference between Nutrient and Pristine mowing?",options:["Pristine includes more trimming detail","Pristine crews spend more time on-site","No — identical service, only difference is clippings are bagged vs mulched","Pristine includes a monthly deep-clean"],answer:2,explanation:"Identical in every way — only clipping handling differs."},
  {id:10,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Does Weekly Lawn Maintenance include fertilizer or weed control?",options:["Yes — fertilizer monthly","Yes — weed control with Pristine","No — it's mowing, string trimming, and blowing only","Only on Property Plans"],answer:2,explanation:"Mowing, string trimming, and blowing. No treatments."},
  {id:11,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"A client asks: \"Does mowing include edging and blowing off my driveway?\" What's the answer?",options:["Only with Pristine Standard","Yes — string trimming around all edges/beds and blowing hard surfaces is standard on every visit, both tiers","Only if they request it each visit","Edging is included but blowing is extra"],answer:1,explanation:"Both tiers include trimming around edges/obstacles/beds + blowing hard surfaces. Every visit."},
  {id:12,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"A client says: \"I heard returning grass clippings causes thatch.\" How should you respond?",options:["Agree and recommend Pristine","Explain that finely mulched clippings break down quickly and don't cause thatch — it's actually great for lawn health","Admit it can be a problem in some cases","Suggest they hire a thatch removal company"],answer:1,explanation:"Common misconception — mulched clippings break down quickly and feed the soil, no thatch issues."},
  {id:13,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What is NOT included in Weekly Lawn Maintenance?",options:["String trimming around obstacles","Blowing hard surfaces","Garden bed weeding or fertilizer","Professional mowing of all turf areas"],answer:2,explanation:"Bed weeding, fertilizer, and treatments are separate services."},
  {id:14,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"An environmentally conscious client wants the healthiest approach for their lawn. Which tier?",options:["Pristine Standard — cleanest lawn","Nutrient Standard — returning clippings feeds the soil naturally","Either — identical for lawn health","Neither — they need a fertilizer program"],answer:1,explanation:"Nutrient Standard is the eco-friendly choice — mulched clippings recycle nutrients."},
  {id:15,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"A client asks about fertilizer, weed control, or grub prevention. What's the correct response?",options:["We offer all of those as add-ons","We offer aeration and overseeding for lawn health but not chemical treatments — suggest a lawn care treatment company for those","We include fertilizer with Pristine Standard","We don't offer anything for lawn health"],answer:1,explanation:"We offer aeration/overseeding. Chemical treatments (fertilizer, weed control, pest) aren't offered — redirect to a specialist."},
  {id:16,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"A client asks: \"What exactly do your guys do when they come for mowing?\" What's the complete answer?",options:["Just mow and leave","Mow all turf, string trim around all edges/beds/obstacles, blow all hard surfaces clean, handle clippings per tier","Mow, fertilize, and edge beds","It depends on the day and crew"],answer:1,explanation:"Every visit: mow all turf, string trim edges/beds/obstacles, blow hard surfaces, clippings handled per tier."},
  {id:17,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"A client asks why they should hire Amigos instead of a neighborhood kid to mow. What's the best differentiator?",options:["We have better mowers","Every visit includes mowing, string trimming all edges, blowing all surfaces — on a reliable weekly schedule with no chasing anyone down","We're cheaper","We guarantee the lawn will be greener"],answer:1,explanation:"Professional quality every visit (mow + trim + blow), reliable schedule, consistency."},
  {id:18,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"A client on Nutrient Standard asks about switching to Pristine. What changes?",options:["Completely different service","Same visit — the only change is clippings are bagged instead of mulched","Pristine includes additional services","You can't switch mid-season"],answer:1,explanation:"Same mowing visit — only clipping handling changes."},

  // ===== SPRING CLEANUP (19-30) =====
  {id:19,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"What does a Spring Cleanup include?",options:["Leaves, sticks, and debris cleared from lawn and beds","Full property cleanup including trimming, pruning, and mulch","Only lawn — beds not touched","Power washing hardscapes"],answer:0,explanation:"Clears debris from lawn and beds — early-season reset."},
  {id:20,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"What's the difference between Nutrient Standard and Pristine Standard Spring Cleanup?",options:["Nutrient is lawn only; Pristine includes beds","Nutrient returns shredded material to soil; Pristine hauls everything away","Pristine includes trimming and pruning","Pristine uses organic products"],answer:1,explanation:"Same scope. Nutrient shreds and returns to soil. Pristine hauls away."},
  {id:21,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"Which is NOT included in a Spring Cleanup?",options:["Clearing debris from lawn","Clearing debris from beds","Trimming, pruning, bed edging, or mulch","Shredding organic material (Nutrient)"],answer:2,explanation:"Does NOT include trimming, pruning, bed edging, or mulch."},
  {id:22,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"A client asks to do spring cleanup AND bush trimming AND mulch at the same time. What's the right response?",options:["Sure — we bundle all of that together","Those are separate services — cleanup first, then beds/mulch, then trimming later in the season","We don't offer trimming","They'd need a different company for mulch"],answer:1,explanation:"Cleanup, trimming, and mulch are separate services with different timing. Offer to quote each separately."},
  {id:23,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"A client asks: \"Can't I just skip the cleanup and start mowing?\" What's the best response?",options:["Sure — cleanup is optional and doesn't matter","Mowing over winter debris can smother grass and trap moisture — cleanup gives your lawn a clean start","If they skip it we charge more for mowing","We require a cleanup before starting mowing"],answer:1,explanation:"Mowing over debris is bad for the lawn. Cleanup creates a clean start for the growing season."},
  {id:24,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"A client asks: \"Does Nutrient Standard mean you put fertilizer down?\" What's the correct answer?",options:["Yes — fertilizer is applied during cleanup","No — it means we shred the debris and return it to the soil to feed it naturally. Pristine hauls everything away instead.","Nutrient and Pristine are the same thing","Only with the premium plan"],answer:1,explanation:"Nutrient = shredded material returned to soil. Not fertilizer. Pristine hauls away."},
  {id:25,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"A client cares more about appearance than soil health. Which Spring Cleanup tier?",options:["Nutrient Standard — barely visible","Pristine Standard — all material hauled away for a perfectly clean result","Either — they look the same","They need a different service"],answer:1,explanation:"Pristine hauls everything away for maximum curb appeal."},
  {id:26,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"Does Spring Cleanup require an active mowing plan?",options:["Yes — add-on to mowing","No — standalone one-time service","Only for Pristine","Only on Property Plans"],answer:1,explanation:"Standalone — no mowing plan required."},
  {id:27,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"A client needs cleanup, beds fixed, bushes trimmed, and mulch. What should you recommend as the first step?",options:["Start with mulch — it covers everything","Start with bush trimming — it's the most visible","Start with Spring Cleanup to clear all winter debris, then tackle beds, mulch, and trimming in order","Do everything on the same day"],answer:2,explanation:"Cleanup first creates a clean baseline. Then beds, mulch, and trimming each in proper order."},
  {id:28,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"A client who cares about long-term soil health should choose which Spring Cleanup tier?",options:["Pristine — cleaner means healthier","Nutrient Standard — shredded material feeds the soil naturally","Doesn't matter","Neither — need a soil treatment"],answer:1,explanation:"Nutrient shreds and returns debris to soil, recycling nutrients naturally."},
  {id:29,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"A client asks: \"Why would I want you to leave debris on my lawn instead of hauling it?\" Best response?",options:["It saves us time and costs you less","We don't just leave it — we finely shred it so it breaks down quickly and feeds your soil. But if you prefer a perfectly clean look, Pristine hauls it all away.","Nutrient is our cheaper option, that's the only difference","You shouldn't — always go Pristine"],answer:1,explanation:"Nutrient isn't 'leaving debris' — it's finely shredded and feeds the soil. Frame both tiers positively."},
  {id:30,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"The Nutrient vs Pristine naming is used for which services?",options:["All services","Mowing, Spring Cleanup, and One-Time Property Cleanup — where material is returned to soil or hauled away","Only mowing","Only winter services"],answer:1,explanation:"Used for services where the choice is return to soil vs haul away."},

  // ===== AERATION & OVERSEEDING (31-48) =====
  {id:31,category:"Service Knowledge",service:"Aeration",type:"mc",question:"What is lawn aeration?",options:["Spraying liquid nutrients into soil","Mechanical core aeration — pulling small soil plugs to loosen compacted ground","Applying a chemical soil loosener","Raking to remove thatch"],answer:1,explanation:"Core aeration — pulling soil plugs to relieve compaction."},
  {id:32,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"What does overseeding do?",options:["Replaces the entire lawn","Thickens existing turf by spreading seed over the current lawn","Kills weeds and replants","Applies seed-and-fertilizer combo"],answer:1,explanation:"Thickens existing turf with new seed."},
  {id:33,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"What does overseeding NOT do?",options:["Improve lawn density","Fill large bare patches or severely damaged areas","Help crowd out weeds","Strengthen root system"],answer:1,explanation:"Does NOT fill large bare patches — needs hydroseeding or renovation."},
  {id:34,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Why is aeration beneficial?",options:["Kills weeds","Relieves soil compaction so air, water, and nutrients reach roots better","Adds fertilizer to root zone","Removes thatch"],answer:1,explanation:"Relieves compaction, improving air/water/nutrient flow to roots."},
  {id:35,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Are Spring Aeration and Spring Overseeding the same service?",options:["Yes — always bundled","No — separate services commonly paired","Aeration includes overseeding","Overseeding includes aeration"],answer:1,explanation:"Separate services, commonly paired but quoted individually."},
  {id:36,category:"Service Knowledge",service:"Aeration",type:"mc",question:"A client asks what aeration is and why they need it. Best explanation?",options:["It's a chemical treatment that softens soil","A machine pulls small soil plugs to relieve compaction — helps air, water, and nutrients reach the roots","It's basically power-raking the lawn","It removes dead grass to allow new growth"],answer:1,explanation:"Machine pulls soil plugs → relieves compaction → better root access to air/water/nutrients."},
  {id:37,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"A client has a big bare patch and asks if overseeding will fix it. What's the honest answer?",options:["Yes — overseeding fills bare patches","Overseeding thickens existing turf but won't fill large bare areas — that needs hydroseeding or renovation","Apply double seed and it will fill in","Bare patches mean the soil is dead and nothing will work"],answer:1,explanation:"Be honest — overseeding is for thickening, not filling large bare areas."},
  {id:38,category:"Service Knowledge",service:"Aeration",type:"mc",question:"A client asks whether spring or fall is better for aeration. What should you say?",options:["Spring is always better","Fall is generally better in Illinois — less weed competition and grass has time to establish before summer heat","It doesn't matter at all","Only do it every other year"],answer:1,explanation:"Fall is stronger recommendation. Both work, but fall has less weed competition."},
  {id:39,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"Why is spring overseeding trickier than fall?",options:["Soil is too cold","Weeds germinate at the same time, and crabgrass preventer can block grass seed","Spring storms wash away seed","Not enough sunlight"],answer:1,explanation:"Spring overseeding competes with weeds, and pre-emergent can block grass seed."},
  {id:40,category:"Service Knowledge",service:"Aeration",type:"mc",question:"A client says their lawn looks fine and asks if they really need aeration. Best response?",options:["No — if it looks fine, skip it","Even healthy lawns benefit — soil compacts naturally over time, and aeration keeps roots healthy. It's like preventive maintenance.","Only if they have visible brown patches","Aeration is only for new lawns"],answer:1,explanation:"Frame as preventive maintenance — soil compacts over time even on healthy lawns."},
  {id:41,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"Is seed material included in the overseeding price?",options:["Client provides their own","Seed cost is embedded — included","Billed separately","Only included with fall"],answer:1,explanation:"Seed cost is embedded in the price."},
  {id:42,category:"Service Knowledge",service:"Aeration",type:"mc",question:"What does a lawn look like right after aeration?",options:["Perfectly smooth","Small soil plugs on the surface — break down in 1-2 weeks","Torn up and needs replanting","Large visible holes"],answer:1,explanation:"Small soil plugs left on surface, break down naturally."},
  {id:43,category:"Service Knowledge",service:"Aeration",type:"mc",question:"A client says their new home's lawn feels rock hard. What should you recommend?",options:["Heavy watering will fix it","Aeration to relieve soil compaction, ideally paired with overseeding to thicken the turf","Replace the entire lawn","Apply a soil softener product"],answer:1,explanation:"Rock-hard lawn = soil compaction. Aeration + overseeding is the right recommendation."},
  {id:44,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Do aeration and overseeding require a mowing plan?",options:["Yes — both require mowing","No — both are standalone one-time services","Only overseeding requires mowing","Only on Property Plans"],answer:1,explanation:"Both are standalone."},
  {id:45,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"A client wants to apply crabgrass preventer AND overseed this spring. What should you tell them?",options:["Go ahead — they work great together","Pre-emergent can block grass seed too — they generally can't do both. Pick one, or defer overseeding to fall which is better timing anyway.","Apply the preventer first, then seed a week later","Overseeding makes preventer unnecessary"],answer:1,explanation:"Pre-emergent blocks grass seed. Choose one or defer seeding to fall."},
  {id:46,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Aeration and Overseeding fall under which service category?",options:["Recurring Lawn Maintenance","Lawn Health","Seasonal Cleanups","Garden Bed Maintenance"],answer:1,explanation:"Both are under Lawn Health."},
  {id:47,category:"Tier Differences",service:"Overseeding",type:"mc",question:"A client with thin grass (but no large bare patches) asks what would help. What should you recommend?",options:["Overseeding — designed to thicken existing turf","Full lawn replacement","Spring Cleanup will help grass grow back","Mulch Installation"],answer:0,explanation:"Overseeding is perfect for thin areas without large bare patches."},
  {id:48,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"For severely damaged lawns, what does Amigos recommend instead of overseeding?",options:["More frequent overseeding","Hydroseeding or renovation (not currently offered by Amigos)","Extra fertilizer","Heavy aeration"],answer:1,explanation:"Severely damaged lawns need hydroseeding or renovation — not currently offered."},

  // ===== GARDEN BED MAINTENANCE (49-72) =====
  {id:49,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Garden Bed Maintenance plans are add-ons to which service?",options:["Spring Cleanup","Mulch Installation","An active mowing plan","Any recurring service"],answer:2,explanation:"Both plans require an active mowing plan."},
  {id:50,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"What method does the Clean Look Plan use to control weeds?",options:["Hand-pulling from root","String trimmers — mechanical weed control (roots stay intact)","Chemical herbicide","Preen weed preventer"],answer:1,explanation:"String trimmers — mechanical trim only, roots remain."},
  {id:51,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"What method does the Estate Detail Plan use?",options:["String trimmers only","Chemical herbicide spray","Hand-pulled weeding plus Preen weed preventer","Full bed replacement"],answer:2,explanation:"Hand-pulled weeding + Preen weed preventer."},
  {id:52,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"What does Preen weed preventer do?",options:["Kills existing weeds on contact","Prevents new weeds from sprouting but does NOT eliminate existing ones","Fertilizes beds","Blocks all plant growth"],answer:1,explanation:"Prevents new weeds from sprouting — doesn't kill existing ones."},
  {id:53,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"A client asks the difference between Clean Look and Estate Detail. What's the most accurate summary?",options:["Clean Look is monthly, Estate Detail is weekly","Clean Look trims weeds mechanically (roots stay); Estate Detail hand-pulls from root and applies Preen to prevent regrowth","Estate Detail covers more bed area","Clean Look uses chemicals, Estate Detail is organic"],answer:1,explanation:"Clean Look = mechanical trim (roots stay). Estate Detail = hand-pull + Preen (roots gone + prevention)."},
  {id:54,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Why do weeds grow back faster on Clean Look than Estate Detail?",options:["Clean Look uses less effective products","Clean Look only cuts at surface — roots remain to regrow","Estate Detail visits more often","Clean Look beds don't get mulch"],answer:1,explanation:"Clean Look trims at surface; roots remain. Estate Detail removes roots and prevents regrowth."},
  {id:55,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Clean Look isn't keeping up with a client's weeds. Best recommendation?",options:["Tell them to water their beds less","Do a Bed Reset to get back to baseline, then consider upgrading to Estate Detail for long-term control","Suggest they just get mulch","Cancel the service — it's not working"],answer:1,explanation:"Bed Reset to baseline, then upgrade to Estate Detail for hand-pulling + Preen."},
  {id:56,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Does Estate Detail require clients to schedule individual weeding visits?",options:["Yes — call each time","No — care is built into the routine automatically spring through fall","Only first visit needs scheduling","Schedule bi-weekly via app"],answer:1,explanation:"No scheduling needed — built into the routine."},
  {id:57,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Which plan includes Preen weed preventer?",options:["Clean Look","Estate Detail","Both","Neither"],answer:1,explanation:"Only Estate Detail includes Preen."},
  {id:58,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"A client wants Estate Detail but doesn't have a mowing plan. What do you tell them?",options:["No problem — Estate Detail is standalone","Both bed plans require a mowing plan since care is built into weekly visits. But standalone options like One-Time Weeding are available.","They need to sign a 2-year contract","Estate Detail doesn't actually require mowing"],answer:1,explanation:"Bed plans require mowing. Offer standalone alternatives and potentially pitch a mowing plan."},
  {id:59,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Which statement best describes Clean Look vs Estate Detail?",options:["Clean Look is cosmetic maintenance; Estate Detail is thorough weed management","Clean Look is monthly; Estate Detail is weekly","Clean Look is for small beds; Estate Detail is for large","Clean Look is manual; Estate Detail uses machinery"],answer:0,explanation:"Clean Look = cosmetic. Estate Detail = thorough."},
  {id:60,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"What should happen before starting a bed plan if beds are overgrown?",options:["Start the plan and catch up over time","A one-time Bed Reset to bring beds to baseline first","Refuse service","Charge double for first month"],answer:1,explanation:"Bed Reset first for a clean baseline, then maintenance keeps them there."},
  {id:61,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"A budget client asks: \"Is Clean Look worth it if weeds grow back?\" Best answer?",options:["Honestly no — just go with Estate Detail","Yes — it controls visible growth like mowing controls grass. For longer-lasting results, Estate Detail pulls roots and prevents regrowth.","Clean Look is a waste of money","Just do one-time weeding instead"],answer:1,explanation:"Clean Look keeps beds neat (like mowing). Estate Detail for longer-lasting control. Both valid."},
  {id:62,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"What is Clean Look Plan's main limitation?",options:["Only covers front yard","If weed growth exceeds capacity, an upgrade or reset may be required","Only for small beds","Doesn't include any trimming"],answer:1,explanation:"If weeds exceed what Clean Look can manage, need upgrade or reset."},
  {id:63,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"A client doesn't want chemicals in their beds. What options can you offer?",options:["We can't help them — all plans use chemicals","Clean Look Plan is purely mechanical (no products). Or Estate Detail without the Preen application.","Only hand-pulling is available at premium prices","We use organic chemicals on all plans"],answer:1,explanation:"Clean Look is chemical-free. Could also do Estate Detail's hand-pulling without Preen."},
  {id:64,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"How often does the crew work on beds under either maintenance plan?",options:["Once a month","Weekly during regular mowing visits","Every other week","Only in spring and fall"],answer:1,explanation:"Built into weekly mowing visits."},
  {id:65,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"For the most thorough, long-lasting weed control, which plan?",options:["Clean Look — covers more area","Estate Detail — hand-pulling + Preen for lasting results","Either — equal prevention","Neither — need herbicide service"],answer:1,explanation:"Estate Detail = hand-pulling + Preen. Most thorough."},
  {id:66,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"A client without a mowing plan wants beds maintained. What standalone option exists?",options:["Clean Look Plan","One-Time Weeding (no plan required)","Estate Detail Plan","No option exists"],answer:1,explanation:"One-Time Weeding is standalone — no mowing plan required."},
  {id:67,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"A client asks what Preen does and why Estate Detail includes it. Best answer?",options:["Preen kills existing weeds on contact","Preen stops new weed seeds from sprouting — paired with hand-pulling, beds stay cleaner longer","Preen is a fertilizer for bed plants","Preen is just a brand name for mulch"],answer:1,explanation:"Preen prevents new weeds from sprouting. Hand-pulling handles existing weeds. Together = longer-lasting results."},
  {id:68,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Client on Clean Look says weeds keep coming back and asks if the plan is doing anything. Best response?",options:["Admit the plan isn't very effective","Explain Clean Look controls visible growth weekly — like mowing. For roots-out results, upgrade to Estate Detail or do a Bed Reset first.","Suggest they cancel","Tell them to pull weeds themselves between visits"],answer:1,explanation:"Validate the concern, explain Clean Look's purpose, offer Estate Detail as upgrade path."},
  {id:69,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"A heavily wooded property with lots of beds would benefit more from which plan?",options:["Clean Look — covers more ground","Estate Detail — thorough hand-pulling prevents overwhelming regrowth","Neither — need full landscaping","Both handle heavy properties equally"],answer:1,explanation:"Heavy weed environments need Estate Detail's thorough approach."},
  {id:70,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"A client asks why they can't get bed maintenance without a mowing plan. What's the real reason?",options:["It's just a business rule with no practical reason","Bed care is built into weekly mowing visits — without weekly presence, quality and pricing can't be maintained","We don't have enough crews for standalone bed work","The equipment is the same"],answer:1,explanation:"Bed care is built into weekly mowing visits. Needs that weekly crew presence."},
  {id:71,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Which bed plan keeps beds cleaner for longer between visits?",options:["Clean Look — it covers beds faster","Estate Detail — pulling roots + Preen means weeds are slower to return","Both are equal","Neither — weeds always come back the same"],answer:1,explanation:"Estate Detail pulls roots AND applies Preen, so regrowth is significantly slower."},
  {id:72,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"A client asks if Preen is safe for their existing plants. What's the answer?",options:["No — Preen kills all plants","Yes — Preen only prevents NEW seeds from germinating. Existing plants are completely safe.","Only safe for certain plant types","It depends on the soil type"],answer:1,explanation:"Preen is a pre-emergent. Only stops new seeds. Existing plants are unaffected."},

  // ===== MULCH INSTALLATION (73-88) =====
  {id:73,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What's included in Mulch Installation?",options:["Delivery, installation, and new bed creation","Delivery, installation, bed edging, and complimentary Preen application","Delivery only — installation extra","Mulch and garden redesign"],answer:1,explanation:"Delivery, installation, bed edging, and Preen."},
  {id:74,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What is NOT included in Mulch Installation?",options:["Bed edging","Preen application","New bed creation or reclaiming undefined areas","Even depth spread"],answer:2,explanation:"Does NOT include new bed creation, expansion, or turf removal."},
  {id:75,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What type of mulch does Amigos install?",options:["Red dyed","Natural dark brown","Cedar chips","Client's choice"],answer:1,explanation:"Natural dark brown mulch."},
  {id:76,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"A client asks what's included with mulch. Which is the most complete answer?",options:["Just the mulch material dropped off","Delivery, installation at even depth, bed edging along borders, and Preen to prevent weeds — existing beds only","Mulch plus new bed creation and planting","Mulch, fertilizer, and weed killer"],answer:1,explanation:"Full package: delivery, install, edging, Preen. Existing beds only."},
  {id:77,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Can Amigos create new flower beds as part of mulch service?",options:["Yes — included","No — existing beds only. No new bed creation or turf removal.","Only small areas","Only in spring"],answer:1,explanation:"Existing beds only. No new beds, expansion, or turf removal."},
  {id:78,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"A client wants to expand beds AND get mulch. What should you tell them?",options:["We'll handle both at once","Mulch covers existing beds only — bed creation or expansion would need to be done separately first, then we can mulch","We don't do mulch unless beds are already perfect","They should find a different company for mulch"],answer:1,explanation:"Mulch = existing beds only. New bed creation is separate and would need to happen first."},
  {id:79,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"A client wants to mulch over weedy beds. What's the right advice?",options:["Go ahead — mulch will smother the weeds","Recommend a Bed Reset first to clear weeds, then mulch with Preen — weeds push through mulch otherwise","Just apply more Preen on top","It depends on the weed type"],answer:1,explanation:"Don't mulch over weeds — they'll push through. Bed Reset first, then mulch."},
  {id:80,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"How does Amigos determine how much mulch a property needs?",options:["Precise measurement with tools","Crew eyeballs it on-site","Client provides the estimate","Calculated from satellite imagery"],answer:1,explanation:"Yardage is estimated on-site by the crew."},
  {id:81,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Is bed edging included with mulch or extra?",options:["Always included","Always extra","Only for large jobs","Only with Property Plans"],answer:0,explanation:"Included with mulch installation."},
  {id:82,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Does Mulch Installation require a mowing plan?",options:["Yes","No — standalone one-time service","Only for large properties","Only for Property Plan clients"],answer:1,explanation:"Standalone — no mowing plan needed."},
  {id:83,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"A client asks about tree rings with mulch. What can you tell them?",options:["We create new tree rings as part of the service","We'll mulch existing tree rings but don't create new ones — new rings require turf removal which is outside this scope","We don't do tree rings at all","Tree rings are only available in fall"],answer:1,explanation:"Existing tree rings: yes. New ring creation: no — requires turf removal."},
  {id:84,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"A client asks how many yards of mulch they need. What should you say?",options:["Calculate it based on their lot size over the phone","We estimate on-site — most standard homes are 3-8 yards. We'll give you an exact quote after seeing the property.","Tell them to measure their beds themselves","Always assume 10 yards"],answer:1,explanation:"Estimated on-site. Give general ranges but quote after seeing the property."},
  {id:85,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What does the Preen application with mulch do?",options:["Kills existing weeds","Prevents new weed seeds from germinating through the mulch","Fertilizes soil","Keeps mulch color from fading"],answer:1,explanation:"Prevents new weed seeds from germinating."},
  {id:86,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Client asks if they should do a bed reset before mulch. What's the right guidance?",options:["Always reset first no matter what","Depends on condition — heavy weeds/debris means reset first, but clean beds just need mulch","Never needed — mulch fixes everything","Only reset if they're on Estate Detail"],answer:1,explanation:"Heavy weeds = reset first. Clean beds = mulch alone is fine."},
  {id:87,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What does 'existing beds only' mean for mulch service?",options:["Only beds with current mulch","Clearly defined beds that already exist — no new beds, turf removal, or expansion","Only front yard beds","Only beds Amigos installed"],answer:1,explanation:"Existing, clearly defined beds. No new bed creation or expansion."},
  {id:88,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"A client asks if they need new mulch when they still have some from last year. Best response?",options:["No — mulch lasts indefinitely","Mulch breaks down, fades, and loses weed-suppressing ability over time — annual refresh maintains appearance and function","Only if it's completely gone","Just add more on top of existing mulch without any prep"],answer:1,explanation:"Mulch degrades over time. Annual refresh maintains look, moisture retention, and weed suppression."},

  // ===== SHRUB & BUSH SHAPING + PERENNIALS (89-106) =====
  {id:89,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"What does Shrub & Bush Shaping involve?",options:["Tree pruning and removal","Professional trimming from ground level using handheld tools — no tree work","Chemical growth inhibitor","Landscape redesign"],answer:1,explanation:"Ground level, handheld tools. No tree work."},
  {id:90,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"How many visits does Annual Shaping include?",options:["1","2","4","6"],answer:0,explanation:"One visit per year."},
  {id:91,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"How many visits does Bi-Annual Shaping include?",options:["1","2","4","6"],answer:1,explanation:"Two visits per year."},
  {id:92,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"How many visits does Premium Managed Shaping include?",options:["2","4","~6 as-needed","12 monthly"],answer:2,explanation:"Approximately 6 as-needed visits."},
  {id:93,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"Which trimming tier requires a mowing plan?",options:["Annual","Bi-Annual","Premium Managed","All three"],answer:2,explanation:"Only Premium Managed requires mowing."},
  {id:94,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"Does Shrub & Bush Shaping include tree work?",options:["Yes — all trees and shrubs","Only small ornamental trees","No — ground level, handheld tools only","Only under 10 feet"],answer:2,explanation:"Ground level only, handheld tools. No tree work."},
  {id:95,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"A client says bushes grow too fast for one annual trim. What should you recommend?",options:["Trim them yourself between visits","Bi-Annual (2 visits/year) or Premium Managed (~6 visits, ongoing) if they have a mowing plan","Annual but with a different crew","We can't help with fast-growing bushes"],answer:1,explanation:"Bi-Annual for moderate growers, Premium Managed for always-maintained look (requires mowing plan)."},
  {id:96,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"A client asks you to trim their trees too. What should you say?",options:["Sure — we handle all plants","Our trimming is ground-level with handheld tools — no tree work. Recommend a certified arborist for trees.","We can do small trees under 8 feet","Tree trimming is included with Premium Managed"],answer:1,explanation:"Ground level only. Redirect to arborist for tree work."},
  {id:97,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"What's the key benefit of Premium Managed over Bi-Annual?",options:["Different equipment","Bushes are trimmed on ongoing as-needed basis — they never look overgrown","Includes tree work","Uses growth retardants"],answer:1,explanation:"Ongoing as-needed = consistently shaped, never overgrown."},
  {id:98,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"Client asks the difference between all three bush trimming tiers. Which summary is correct?",options:["They're all the same, just different prices","Annual (1 visit/year), Bi-Annual (2/year), Premium Managed (~6 ongoing visits, requires mowing plan)","Annual is basic tools, Bi-Annual is power tools, Premium uses heavy equipment","Annual is front yard, Bi-Annual is full property, Premium adds backyard"],answer:1,explanation:"Annual=1, Bi-Annual=2, Premium Managed=~6 ongoing (requires mowing plan)."},
  {id:99,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"Can a client without a mowing plan get Annual or Bi-Annual Shaping?",options:["No — all require mowing","Yes — only Premium Managed requires mowing","Only Annual","Need at least bed maintenance"],answer:1,explanation:"Annual and Bi-Annual are standalone. Only Premium Managed requires mowing."},
  {id:100,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"What does 'ground level only' mean for trimming?",options:["Only trim at ground level","Work from ground with handheld tools — no ladders, climbing, or overhead work","Only bushes under 3 feet","Crew stays on flat ground only"],answer:1,explanation:"Ground level, handheld tools. No ladders, climbing, or overhead."},
  {id:101,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"A client on a mowing plan says their bushes look terrible between trims. Best recommendation?",options:["Trim them yourself between our visits","Premium Managed Shaping — ongoing trimming built into your existing mowing visits, about 6 times per season","Switch to a different landscaper","Add more mulch around the bushes"],answer:1,explanation:"Since they have mowing, Premium Managed is perfect — built into existing visits."},
  {id:102,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"A client says their neighbor's bushes look perfect all summer. What service achieves that?",options:["Annual Shaping with a good crew","Premium Managed Shaping — ongoing as-needed trimming so bushes never look overgrown","Bi-Annual Shaping plus fertilizer","It depends on the bush variety"],answer:1,explanation:"Premium Managed = ongoing care, always maintained look."},
  {id:103,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"What is Perennial Flower Pruning?",options:["Trimming shrubs and trees","Seasonal pruning of perennial flowers — typically spring and fall cut-backs","Removing dead annuals","Planting new perennials"],answer:1,explanation:"Seasonal pruning at appropriate times — spring and/or fall."},
  {id:104,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"A client asks if you handle their perennial flowers, not just bushes. What's the answer?",options:["No — we only do bushes","Yes — Perennial Flower Pruning is available as an add-on with spring and fall cut-backs, separate from bush trimming","Only if they're on Estate Detail for beds","Perennial care is included with mowing"],answer:1,explanation:"Perennial Flower Pruning is a separate add-on. Spring + fall cut-backs."},
  {id:105,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"Does Perennial Flower Pruning include shrub or tree trimming?",options:["Yes — all plants","Only small shrubs","No — perennial flowers only","Only near perennials"],answer:2,explanation:"Perennial flowers only. Shrubs and trees are separate."},
  {id:106,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"What's the difference between perennial pruning and bush trimming?",options:["They're the same service","Bush trimming shapes shrubs with tools; perennial pruning is seasonal flower maintenance — different plants, timing, and technique","Perennial pruning is more expensive","Bush trimming is more thorough"],answer:1,explanation:"Different plants, different timing, different technique. Separate services."},

  // ===== LEAF CARE (107-132) =====
  {id:107,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Recurring Leaf Care requires what?",options:["Garden Bed Maintenance","A mowing plan","Snow Removal","Spring Cleanup"],answer:1,explanation:"Requires an active mowing plan."},
  {id:108,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What does Standard Leaf Care include?",options:["Leaves hauled away every visit","Leaves mulched into turf weekly + deep cleanup at season end","Full property cleared every visit","One cleanup at end only"],answer:1,explanation:"Mulched weekly, deep cleanup at end."},
  {id:109,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What does Pristine Leaf Care include?",options:["Mulched weekly","Collected and hauled away from lawn and hardscapes every visit + comprehensive final cleanup","Same as Standard with extra cleanup","Beds cleared every visit"],answer:1,explanation:"Hauled away from lawn/hardscapes every visit + comprehensive final cleanup."},
  {id:110,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What makes Estate Leaf Care different from Pristine?",options:["Just a bigger version","Clears lawn, hardscapes, AND all flower beds every visit — property stays immaculate","Includes snow removal","Runs through December"],answer:1,explanation:"Completely clears lawn, hardscapes, AND all beds every visit. Most comprehensive."},
  {id:111,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A client asks about all three leaf care levels. Which is the correct summary?",options:["They're basically the same, just different prices","Standard mulches weekly; Pristine hauls away from lawn/hardscapes weekly; Estate clears everything including beds every visit","Standard is monthly, Pristine is weekly, Estate is daily","Standard covers lawn, Pristine adds driveway, Estate adds beds"],answer:1,explanation:"Standard=mulch, Pristine=haul from lawn/hardscapes, Estate=clear everything including beds."},
  {id:112,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"Which tier clears flower beds during every visit?",options:["Standard","Pristine","Estate","All three"],answer:2,explanation:"Only Estate clears beds every visit."},
  {id:113,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Does leaf care replace mowing or is mowing still billed separately?",options:["Leaf care replaces mowing","Mowing continues alongside leaf care — it's an add-on, not a replacement","Only Standard replaces mowing","Mowing switches to monthly during leaf season"],answer:1,explanation:"Mowing continues. Leaf Care is an add-on."},
  {id:114,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"A client doesn't want weekly leaf care — just one cleanup at the end. What service should you recommend?",options:["Standard Leaf Care","One-Time Property Cleanup — single comprehensive visit with Nutrient (return to soil) or Pristine (haul away) options","Tell them we only do recurring","Suggest they rake it themselves"],answer:1,explanation:"One-Time Property Cleanup is the single-visit alternative."},
  {id:115,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A Standard client says their neighbor's trees dump tons of leaves and Standard isn't keeping up. What do you suggest?",options:["Add a second Standard plan","Upgrade to Pristine (haul-away weekly) or Estate (clears everything including beds) — pricing already factors in leaf volume","Switch to one-time cleanup instead","Tell them leaf care can't handle heavy volume"],answer:1,explanation:"Suggest Pristine or Estate upgrade. Leaf volume multiplier already accounts for heavy properties."},
  {id:116,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A client says they just want their property to \"look decent\" — not perfect. Which tier?",options:["Estate — go big","Standard — mulches weekly to control buildup, deep cleanup at end. Won't be leaf-free every week but stays managed.","Pristine — minimum for any visible results","They don't need leaf care at all"],answer:1,explanation:"Standard is right for 'decent' expectations. Easy to upgrade later."},
  {id:117,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"What's the benefit of Standard Leaf Care's mulching approach?",options:["It's faster for the crew","Mulched leaves return nutrients to the soil","It prevents new weed growth","Eliminates the need for final cleanup"],answer:1,explanation:"Mulched leaves return nutrients to soil — same Nutrient philosophy."},
  {id:118,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A Pristine client asks why there are still leaves in their flower beds. What's the explanation?",options:["The crew must have missed them — we'll come back","Pristine covers lawn and hardscapes weekly — beds are addressed at the final cleanup. Estate clears beds every visit.","Pristine doesn't cover beds at all","That's normal and there's nothing we can do"],answer:1,explanation:"Pristine = lawn/hardscapes weekly, beds at final cleanup. Estate = everything every visit."},
  {id:119,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A budget client is choosing between Standard and Pristine. What's the key difference to help them decide?",options:["Standard is half the price of Pristine","Standard has some leaf coverage between visits but is affordable; Pristine keeps it clean weekly but costs more. Depends on their tolerance for visible leaves.","Standard doesn't include a final cleanup","Pristine is only worth it for large properties"],answer:1,explanation:"Standard = some coverage between visits, affordable. Pristine = clean weekly, more cost."},
  {id:120,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"A client asks if there's a final cleanup at the end of leaf season. What's the answer?",options:["Only with Estate tier","Yes — all tiers include a final cleanup. Standard does a deep cleanup, Pristine does a comprehensive one including all beds.","No — the last weekly visit is the last visit","Final cleanup is a separate charge"],answer:1,explanation:"All tiers include a final cleanup. Scope varies by tier."},
  {id:121,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A client wants flower beds clear of leaves all fall, not just at the end. Which tier?",options:["Standard — final cleanup covers beds","Pristine — beds cleared at final cleanup","Estate — beds cleared during every weekly visit all season","Any tier covers beds weekly"],answer:2,explanation:"Only Estate clears beds every visit throughout the season."},
  {id:122,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What does Pristine's final cleanup include beyond Standard's?",options:["They're identical","Pristine's final comprehensively clears all landscape beds","Gutter cleaning","Roof clearing"],answer:1,explanation:"Pristine's final is comprehensive, including all landscape beds."},
  {id:123,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A client wants their entire property leaf-free all fall. Which tier?",options:["Standard","Pristine","Estate","Standard + separate bed cleanup"],answer:2,explanation:"Estate = full property cleared every visit."},
  {id:124,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"A client says their property has way more trees than neighbors. Does that affect price?",options:["No — leaf care is flat rate","Yes — pricing factors in leaf volume. Heavier coverage costs more since there's more work each visit.","Only if they have more than 10 trees","It only matters for Estate tier"],answer:1,explanation:"Leaf volume is factored into pricing. Heavier coverage = higher price."},
  {id:125,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"A client with a visible front yard who entertains regularly. Which leaf care tier?",options:["Standard — mulching is fine","Pristine — hauled away weekly for a consistently clean look","Estate — but only if they have beds","Standard with extra visits"],answer:1,explanation:"Pristine hauls away weekly — ideal for clients who want property looking clean for guests."},
  {id:126,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"A client asks if recurring leaf care is worth it vs just the one-time cleanup. What's the key difference?",options:["Recurring and one-time are the same service at different times","Recurring manages leaves weekly all fall (stays clean). One-time is one big clean at the end (leaves accumulate). One-time costs less.","Recurring is always better","One-time is always better"],answer:1,explanation:"Recurring = clean all fall. One-time = accumulate, one clean, less cost."},

  // ===== ONE-TIME PROPERTY CLEANUP + BED SERVICES (127-146) =====
  {id:127,category:"Service Knowledge",service:"One-Time Property Cleanup",type:"mc",question:"One-Time Property Cleanup is the alternative to?",options:["Spring Cleanup","Garden Bed Maintenance","Recurring Leaf Care","Mowing"],answer:2,explanation:"Single-visit alternative to recurring Leaf Care."},
  {id:128,category:"Tier Differences",service:"One-Time Property Cleanup",type:"mc",question:"What are the two tiers for One-Time Property Cleanup?",options:["Standard and Premium","Nutrient Standard (return to soil) and Pristine Standard (haul away)","Basic and Complete","Clean Look and Estate Detail"],answer:1,explanation:"Nutrient = return to soil. Pristine = haul away."},
  {id:129,category:"Service Knowledge",service:"One-Time Property Cleanup",type:"mc",question:"Does One-Time Property Cleanup require a mowing plan?",options:["Yes","No — standalone one-time","Only Pristine","Only Property Plan clients"],answer:1,explanation:"Standalone — no mowing plan."},
  {id:130,category:"Service Knowledge",service:"One-Time Property Cleanup",type:"mc",question:"What's the difference between seasonal leaf care and the one-time cleanup?",options:["They're the same service","Seasonal is weekly management all fall (stays clean); one-time is a single visit (leaves accumulate first). One-time costs less.","One-time is more thorough","Seasonal covers more area"],answer:1,explanation:"Seasonal = weekly, clean all fall. One-time = single visit, leaves build up first."},
  {id:131,category:"Service Knowledge",service:"Bed Reset / Garden Cleanup",type:"mc",question:"What is a Bed Reset?",options:["Installing new plants","Thorough one-time cleanup — removes weeds, debris, dead plants, brings beds to clean baseline","Chemical weed killer application","Replacing mulch"],answer:1,explanation:"Thorough cleanup bringing beds to a clean baseline."},
  {id:132,category:"Service Knowledge",service:"Bed Reset / Garden Cleanup",type:"mc",question:"Bed Reset is commonly done before what?",options:["Spring Cleanup and Aeration","Mulch Installation or starting a bed maintenance plan","Snow Removal","Overseeding"],answer:1,explanation:"Common prerequisite before mulch or maintenance plan."},
  {id:133,category:"Service Knowledge",service:"One-Time Weeding",type:"mc",question:"What is One-Time Weeding?",options:["Full garden redesign","Single visit to clear weeds — basic (trimmer) or detail (hand-pull). No commitment.","Chemical herbicide application","Weed barrier fabric installation"],answer:1,explanation:"Single visit, basic or detail, no commitment."},
  {id:134,category:"Service Knowledge",service:"Bed Edging",type:"mc",question:"What does Bed Edging do?",options:["Installs metal edging","Defines and restores clean borders between lawn and flower beds","Cuts new beds from lawn","Removes existing edging"],answer:1,explanation:"Defines and restores clean borders."},
  {id:135,category:"Service Knowledge",service:"Bed Edging",type:"mc",question:"Is Bed Edging included with Mulch or separate?",options:["Separate always","Typically included with Mulch, also available standalone","Only for large properties","Only with Estate Detail"],answer:1,explanation:"Included with mulch, also available standalone."},
  {id:136,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"New homeowner's beds are a mess. They want cleanup, mulch, and ongoing maintenance. What's the correct order?",options:["Mulch first, then clean up, then maintenance","Bed Reset first → Mulch second → then recurring maintenance plan (requires mowing)","Start maintenance plan immediately — it'll catch up","Just do mulch — it covers everything"],answer:1,explanation:"Reset to baseline → Mulch → then ongoing maintenance. Each quoted separately."},
  {id:137,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"Do One-Time Bed Services require a mowing plan?",options:["Yes — all","No — all standalone","Only Bed Reset","Only Bed Edging"],answer:1,explanation:"All standalone — no mowing plan required."},
  {id:138,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"Client just wants weeds pulled once — nothing ongoing. What service fits?",options:["They must sign up for a maintenance plan","One-Time Weeding — single visit, basic (trimmer) or detail (hand-pull), no commitment","Bed Reset is the only option","We don't offer one-time services"],answer:1,explanation:"One-Time Weeding, basic or detail. No commitment."},
  {id:139,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"A client wants beds cleaned up once with no ongoing commitment. What can you offer?",options:["Only recurring maintenance plans","One-time bed services: Bed Reset for a full overhaul, One-Time Weeding for just weeds. One invoice, done.","They need a mowing plan first","We require a 6-month minimum"],answer:1,explanation:"One-time services: Bed Reset or One-Time Weeding. No commitment."},
  {id:140,category:"Service Knowledge",service:"One-Time Weeding",type:"mc",question:"What's the difference between 'basic' and 'detail' One-Time Weeding?",options:["Front yard vs full property","Basic uses trimmer (roots stay); detail is hand-pulled from root (more thorough)","One visit vs two visits","Chemical vs organic"],answer:1,explanation:"Basic = trimmer, roots stay. Detail = hand-pull from root."},
  {id:141,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"What's the difference between a Bed Reset and One-Time Weeding?",options:["They're the same service at different prices","Reset is comprehensive (weeds + dead plants + debris — back to baseline). Weeding is lighter (just clearing weed growth specifically).","Reset is for front yard, weeding is for back","Reset uses chemicals, weeding doesn't"],answer:1,explanation:"Reset = comprehensive overhaul. Weeding = just weed removal."},
  {id:142,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"Which service is the most common prerequisite before mulch?",options:["One-Time Weeding","Bed Edging","Bed Reset / Garden Cleanup","Perennial Pruning"],answer:2,explanation:"Bed Reset is the common prerequisite before mulch."},
  {id:143,category:"Service Knowledge",service:"Bed Edging",type:"mc",question:"A client says grass is growing into their beds and the borders look messy. What service fixes this?",options:["Mulch Installation","Bed Edging — restores clean borders between lawn and beds. Included with mulch or available standalone.","Spring Cleanup","Aeration"],answer:1,explanation:"Bed Edging defines and restores clean borders."},
  {id:144,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"Client says beds are \"okay-ish\" — not terrible but not great. Best recommendation?",options:["They need a full Bed Reset","One-Time Weeding (basic or detail), then suggest mulch to level up the look, then mention maintenance plans for ongoing care","Skip straight to a maintenance plan","They don't need anything"],answer:1,explanation:"Match to their situation: weeding first, mulch to level up, mention maintenance."},

  // ===== SNOW REMOVAL & SALT (145-168) =====
  {id:145,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Standard Snow Removal triggers at?",options:["Any trace","~1 inch","~2 inches","~4 inches"],answer:2,explanation:"Standard: ~2 inches."},
  {id:146,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Premium Snow Removal triggers at?",options:["Any trace","~1 inch","~2 inches","~3 inches"],answer:1,explanation:"Premium: ~1 inch."},
  {id:147,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Zero Tolerance triggers at?",options:["~1 inch","~0.5 inch","Any accumulation (trace)","Only ice events"],answer:2,explanation:"Any accumulation — property stays clear at all times."},
  {id:148,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"How many visits per qualifying snow event?",options:["1","2","3","Unlimited"],answer:3,explanation:"Unlimited visits per event across all tiers."},
  {id:149,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Snow Removal covers what areas?",options:["Entire property","Designated driveways and walkways","Only driveway","Driveway, walkways, and roof"],answer:1,explanation:"Designated driveways and walkways."},
  {id:150,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Service hours for Snow Removal?",options:["Business hours only","Extended (6am-10pm)","24/7","On-call only"],answer:2,explanation:"All tiers: 24/7."},
  {id:151,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Besides a lower trigger, what does Premium add over Standard?",options:["Sidewalk shoveling","Priority dispatch and earlier response window","Salt included","Roof clearing"],answer:1,explanation:"Priority dispatch and earlier response."},
  {id:152,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Client asks the difference between Standard and Premium snow removal. What's the most important distinction?",options:["Standard is residential, Premium is commercial","Standard triggers at ~2 inches; Premium triggers at ~1 inch with priority dispatch and earlier response. Both have unlimited visits 24/7.","Premium includes salt treatment","Standard is seasonal, Premium is per-event"],answer:1,explanation:"Trigger level and priority response are the key differences."},
  {id:153,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Client has elderly parents and cannot have ANY snow — fall risk. Which tier?",options:["Standard — it covers most situations","Premium — lower trigger helps","Zero Tolerance — triggers at any trace of accumulation, highest priority, property stays clear at all times","They need a private plow service"],answer:2,explanation:"Zero Tolerance: any trace trigger, highest priority, always clear. Perfect for safety-critical situations."},
  {id:154,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Client says they handle light snow themselves and only want help for bigger storms. Which tier?",options:["Zero Tolerance","Premium","Standard — triggers at ~2 inches so light snow won't activate visits. Unlimited visits for qualifying events, 24/7.","They don't need a plan"],answer:2,explanation:"Standard at ~2 inches is perfect — light snow doesn't trigger, big storms are covered."},
  {id:155,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"A client asks if there's a limit on how many times you'll come during a big storm. Answer?",options:["Maximum 3 visits per event","Unlimited visits per qualifying event — we keep coming back as needed, 24/7","It depends on the tier","One visit per storm"],answer:1,explanation:"Unlimited visits per event. All tiers."},
  {id:156,category:"Service Knowledge",service:"Salt Treatment",type:"mc",question:"What is Salt Treatment?",options:["Standalone winter service","Add-on: ice-melt applied to walkways and driveways after snow clearing","Pre-treatment before snowfall","Included with all tiers"],answer:1,explanation:"Add-on: ice-melt after clearing for traction."},
  {id:157,category:"Service Knowledge",service:"Salt Treatment",type:"mc",question:"Is Salt Treatment included with Snow Removal?",options:["Included with all tiers","Included with Premium/Zero Tolerance only","Separate add-on for all tiers","Only with Zero Tolerance"],answer:2,explanation:"Separate add-on for any tier."},
  {id:158,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"A daily commuter with a long driveway asks which snow tier. Best recommendation?",options:["Standard — 2 inches is reasonable","Premium — earlier response and priority dispatch for people who need it clear before work","Zero Tolerance — only option for commuters","They should buy a snow blower"],answer:1,explanation:"Premium's priority dispatch and earlier response is ideal for commuters."},
  {id:159,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"A client asks what Zero Tolerance means. Best explanation?",options:["We have zero tolerance for late service","Triggers at any trace of snow — highest priority dispatch, property stays completely clear at all times","We guarantee arrival within 30 minutes","It means we salt before it snows"],answer:1,explanation:"Any trace trigger, highest priority, property always clear."},
  {id:160,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Client asks if there's a visit limit during big storms. What's the answer?",options:["3 per event maximum","Unlimited — we keep coming back as needed, 24/7. No cap.","Depends on your tier","1 per event, then extra charges"],answer:1,explanation:"Unlimited visits per event. All tiers."},
  {id:161,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Client asks what areas you actually clear — just driveway or walkways too?",options:["Driveway only","Designated driveways and walkways — we define exactly what's covered when setting up the plan","Every paved surface plus the lawn","Depends on crew availability"],answer:1,explanation:"Driveways and walkways. Scope defined at setup."},
  {id:162,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Client asks if you salt after plowing. What's the correct response?",options:["Salt is always included","Salt Treatment is an optional add-on to any snow removal tier — applied after clearing for traction and icing reduction","We only salt for Zero Tolerance clients","We don't offer salt at all"],answer:1,explanation:"Salt is a separate add-on, not automatic. Available with any tier."},
  {id:163,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Work-from-home client wants reliable service when it snows, no urgency. Best tier?",options:["Zero Tolerance","Standard — reasonable for regular needs, triggers at ~2 inches, 24/7, unlimited","Premium — everyone needs priority","They don't need snow removal"],answer:1,explanation:"Standard is appropriate for regular needs without urgent timing."},
  {id:164,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Client leaves for work at 5 AM and needs driveway clear early. Which tier?",options:["Standard — 24/7 covers morning","Premium — priority dispatch and earlier response window means they're cleared sooner","Zero Tolerance is the only option","Custom arrangement needed"],answer:1,explanation:"Premium's priority dispatch and earlier response is designed for exactly this."},
  {id:165,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Client asks when snow removal starts/stops and if they need to call each time. Answer?",options:["Call us each time it snows","Plan covers first snowfall through March 31 — automatic dispatch when snow hits your trigger level. No calls needed.","November 1 through February 28, call to activate","Only during declared snow emergencies"],answer:1,explanation:"First snowfall through March 31. Automatic dispatch. No calls needed."},

  // ===== PROPERTY PLAN vs AS-NEEDED (166-184) =====
  {id:166,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"What are the two ways clients can book services?",options:["Monthly subscription or pay-per-visit","As-Needed (individual jobs) or Property Plan (custom membership)","Residential or commercial","DIY or full-service"],answer:1,explanation:"As-Needed or Property Plan."},
  {id:167,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"How is a Property Plan billed?",options:["Lump sum","Per service completed","12 monthly installments","Quarterly"],answer:2,explanation:"12 monthly installments."},
  {id:168,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"What do clients get for pre-paying a Property Plan for the full year?",options:["10% discount","1 month free","Free spring cleanup","No incentive"],answer:1,explanation:"Pre-pay = 1 month free."},
  {id:169,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"What scheduling benefit do plan members get?",options:["Weekend scheduling","Priority scheduling for one-off requests","Same-day guarantee","No benefit"],answer:1,explanation:"Priority scheduling for one-off requests."},
  {id:170,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client asks why a Property Plan instead of calling when they need something. Best selling point?",options:["It's cheaper per service","Everything pre-scheduled, one monthly payment, priority scheduling, and pre-pay gets a month free — vs scheduling individually with no priority","We require a plan for most services","You get a dedicated crew"],answer:1,explanation:"Pre-scheduled, consistent billing, priority, pre-pay savings."},
  {id:171,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client wants mowing, leaf care, and snow removal. Should you pitch a Property Plan?",options:["No — book each separately as-needed","Yes — multiple recurring services spanning most of the year is the ideal Property Plan candidate","Only if they want all premium tiers","Property Plans are only for full-service clients"],answer:1,explanation:"Multiple recurring services = perfect for a Property Plan."},
  {id:172,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client only wants mulch and one-time weeding. Should you push a Property Plan?",options:["Yes — every client should be on a plan","No — those are one-time services perfect for As-Needed booking. Leave the door open for future recurring needs.","Only if they add mowing","Plans are required for all services"],answer:1,explanation:"One-time services = As-Needed is the right fit. No need to push a plan."},
  {id:173,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Can clients book any service As-Needed without a plan?",options:["No — some require a plan","Yes — any service can be booked individually","Only one-time services","Only under $500"],answer:1,explanation:"Any service can be booked individually."},
  {id:174,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Which services REQUIRE a mowing plan as prerequisite?",options:["Spring Cleanup and Mulch","Garden Bed Maintenance, Leaf Care, and Premium Managed Shaping","All except snow removal","Only Garden Bed Maintenance"],answer:1,explanation:"Garden Bed Maintenance, Leaf Care, and Premium Managed Shaping."},
  {id:175,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Competitor offers one price for everything. Client asks if you can match. Best response?",options:["Sure — we'll match any price","We build every plan custom to each property — you only pay for what makes sense. One-size-fits-all usually means overpaying or corners being cut.","We're more expensive but worth it","We don't do that kind of pricing"],answer:1,explanation:"Custom plans = pay for what you need. One-size-fits-all = overpaying or corners cut."},
  {id:176,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client asks how the pre-pay discount works. What's the correct explanation?",options:["10% off the total","Pre-pay the full year and get one month free — pay 11 months instead of 12","Free spring cleanup with annual payment","First month free then regular payments"],answer:1,explanation:"Pay 11 months instead of 12 = 1 month free."},
  {id:177,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client asks what happens if they need something not on their plan. Answer?",options:["They can't get anything outside the plan","Plan members get priority scheduling for one-off requests — we quote it separately and schedule it. Plans give you better access, not less.","They have to upgrade their plan first","One-off jobs aren't available to plan members"],answer:1,explanation:"Priority scheduling for one-off requests. Plan = better access."},
  {id:178,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client isn't sure about committing to a full year. Best response?",options:["It's all or nothing — full year or no plan","Start with just mowing and add services anytime as seasons change. No pressure to do everything upfront.","We require at least 3 services to start a plan","We offer a 3-month trial"],answer:1,explanation:"Start small, add over time. Meet them where they are."},
  {id:179,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Key advantage of a plan for multi-service clients?",options:["Lower per-service prices","Pre-scheduled everything, one monthly payment, priority scheduling","Dedicated crew","Same-day service guarantee"],answer:1,explanation:"Pre-scheduled, consistent billing, priority scheduling."},
  {id:180,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Client asks if the Property Plan is a contract they can't get out of. Best response?",options:["Yes — it's a binding annual contract","It's a membership with pre-scheduled services and 12 monthly payments. For specific cancellation details, I'd want to make sure I give you the right info — but the goal is to make it beneficial, not to lock you in.","You can cancel anytime with no consequences","There's a large cancellation fee"],answer:1,explanation:"Frame as membership. Don't make cancellation promises you can't verify. Focus on benefits."},

  // ===== CROSS-SERVICE & GENERAL (181-200) =====
  {id:181,category:"Service Knowledge",service:"General",type:"mc",question:"A client asks what most customers typically get. What's the most common service combo?",options:["Just mowing","Mowing + leaf care + snow removal on a Property Plan — covers most of the year with one monthly payment","Everything at the highest tier","Only spring and fall cleanups"],answer:1,explanation:"Mowing + leaf care + snow is the common combo. Property Plan ties it together."},
  {id:182,category:"Service Knowledge",service:"General",type:"mc",question:"A client getting quotes from multiple companies asks why they should choose Amigos. Best differentiator?",options:["We're the cheapest","Custom plans per property, pre-scheduled, one monthly payment, priority scheduling, and pre-pay gets a month free","We've been in business the longest","We use the best equipment"],answer:1,explanation:"Custom plans, pre-scheduled, consistent billing, priority, pre-pay savings."},
  {id:183,category:"Service Knowledge",service:"General",type:"mc",question:"Which service does Amigos NOT offer?",options:["Aeration","Irrigation/sprinkler maintenance","Snow removal","Trimming & Pruning"],answer:1,explanation:"Irrigation is not offered."},
  {id:184,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks if Amigos can handle everything for their property. What's the honest answer?",options:["Yes — we do absolutely everything","We cover lawn maintenance, bed care, seasonal services, and snow removal. We don't do landscape design, plantings, hardscaping, tree work, or chemical treatments.","We only do mowing and snow","It depends on the property size"],answer:1,explanation:"Be honest about what we do and don't do."},
  {id:185,category:"Service Knowledge",service:"General",type:"mc",question:"Client had a bad experience with a landscaper who kept upselling. How should you position Amigos?",options:["Promise you'll never suggest anything additional","We recommend based on what your property actually needs — if something doesn't make sense, we won't push it","Avoid mentioning any services beyond what they ask about","Offer a discount to win them over"],answer:1,explanation:"Consultative approach — recommend what fits, don't push what doesn't."},
  {id:186,category:"Service Knowledge",service:"General",type:"mc",question:"Client wants 'the full treatment — everything, year-round.' Which combination covers them?",options:["Mowing and mulch","Spring Cleanup → Aeration/Overseeding → Mowing → Bed Maintenance → Mulch → Bush Trimming → Perennial Pruning → Leaf Care → Snow Removal + Salt, all on a Property Plan","Mowing + snow removal covers everything","We don't offer year-round service"],answer:1,explanation:"Full seasonal calendar of services on a Property Plan."},
  {id:187,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks why some services need a mowing plan. What's the real reason?",options:["It's a business rule to sell more mowing","Those services are built into weekly mowing visits — it keeps quality consistent and pricing efficient","We don't have separate crews for bed work","It's required by our insurance"],answer:1,explanation:"Built into weekly visits for efficiency and consistency."},
  {id:188,category:"Service Knowledge",service:"General",type:"mc",question:"Which services require an active mowing plan?",options:["Garden Bed Maintenance + Mulch + Aeration","Garden Bed Maintenance + Leaf Care + Premium Managed Shaping","All recurring services","Only Garden Bed Maintenance"],answer:1,explanation:"Garden Bed Maintenance, Leaf Care, and Premium Managed Shaping."},
  {id:189,category:"Service Knowledge",service:"General",type:"mc",question:"New client calls in fall. Which services are relevant right now?",options:["Only snow removal","Fall Aeration/Overseeding, Leaf Care (or One-Time Cleanup), Snow Removal approaching, and possibly mowing for the tail end of season","Spring Cleanup","Mulch Installation"],answer:1,explanation:"Fall services: aeration, leaf care, snow upcoming, possibly late-season mowing."},
  {id:190,category:"Service Knowledge",service:"General",type:"mc",question:"A Property Plan client asks in August what's been done and what's coming. Which is the correct season summary?",options:["Everything is done — nothing left until spring","Spring cleanup, aeration, mowing, bed care, mulch, and trimming done. Coming up: fall aeration in September, leaf care October-November, then snow removal for winter.","Only mowing has been done so far","Snow removal starts next month"],answer:1,explanation:"Show confidence in the full service calendar — recap done + upcoming."},
  {id:191,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks what happens first if they start a plan now. Correct answer?",options:["We start everything at once","We assess the property, build a custom plan, start whatever's in season immediately, schedule the rest for the year — one monthly payment covers it all","They have to wait until January","We send a survey first"],answer:1,explanation:"Assessment → custom plan → current season starts immediately → one monthly payment."},
  {id:192,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks what happens if it rains on mowing day. Correct answer?",options:["We skip it and you get a credit","We adjust within the week — pricing doesn't change based on timing. Weather adjustments are part of the service.","We come in the rain regardless","You lose that visit"],answer:1,explanation:"Adjust within the week. Pricing doesn't change. Part of the service."},
  {id:193,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks for a ballpark on mowing and basic bed care. What should you tell them?",options:["Give an exact price over the phone","Explain the options (Nutrient vs Pristine mowing, Clean Look vs Estate Detail beds) and say you need to see the property for exact pricing","Tell them to check the website","Refuse to discuss pricing"],answer:1,explanation:"Explain service options, note that exact pricing needs a property assessment."},
  {id:194,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks about landscape design, plantings, or hardscaping. What should you say?",options:["We offer those as premium add-ons","We focus on maintenance — we don't do design, plantings, or hardscaping. Suggest a landscape design company. But we're great at maintaining what's already there.","We can subcontract that for them","Avoid the question"],answer:1,explanation:"Be honest. Redirect to specialists. Position as maintenance partner."},
  {id:195,category:"Service Knowledge",service:"General",type:"mc",question:"Client selling their house asks what makes the biggest visual impact. Best recommendation?",options:["Just mow more frequently","Fresh mulch (instant impact), Pristine mowing, bush trimming, and a Bed Reset if beds have weeds — premium tiers are worth it for selling","Only focus on the front yard","Aeration and overseeding is most important for selling"],answer:1,explanation:"Mulch for instant impact + Pristine + trimming + bed reset if needed. Appearance matters for selling."},
  {id:196,category:"Service Knowledge",service:"General",type:"mc",question:"Client says a competitor claimed returning clippings causes thatch and disease. Response?",options:["The competitor is right — go with Pristine","That's a common misconception — finely mulched clippings break down quickly and feed the soil. Offer Pristine as an alternative if they prefer the clean look.","Refuse to comment on competitors","Agree it's risky and upsell Pristine"],answer:1,explanation:"Address the misconception, support Nutrient with facts, offer Pristine as preference-based alternative."},
  {id:197,category:"Service Knowledge",service:"General",type:"mc",question:"Budget client asks for the minimum they should do for their lawn. Best recommendation?",options:["Everything or nothing — no point in half-measures","Nutrient Standard mowing as baseline, aeration once a year, and Clean Look for beds if needed — start there, add later","They should just do it themselves","We require a minimum of 3 services"],answer:1,explanation:"Nutrient mowing baseline, aeration annually, Clean Look for beds. Don't overwhelm budget clients."},
  {id:198,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks if there are hidden fees with mulch. Best response?",options:["There are additional charges for delivery","Price per yard includes everything: delivery, install, edging, and Preen. Only exclusion is new bed creation. What you're quoted is what you pay.","Setup fee applies to new clients","Materials are billed separately"],answer:1,explanation:"All-inclusive: delivery, install, edging, Preen. No hidden fees. Transparent."},
  {id:199,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks about package deals or discounts. What should you tell them?",options:["We don't offer discounts","The Property Plan is our best deal — bundled services, 12 monthly payments, priority scheduling. Pre-pay the full year and get one month free.","First-time customers get 50% off","Discounts only during winter"],answer:1,explanation:"Property Plan = the package deal. Pre-pay = 1 month free."},
  {id:200,category:"Service Knowledge",service:"General",type:"mc",question:"Client asks what one service they should start with if they're new to Amigos. Best answer?",options:["Mulch — it makes the biggest visual impact","Weekly mowing — it's the foundation that unlocks other services like bed care and leaf care. Start there, add more later.","Aeration — fix the lawn first","Spring Cleanup regardless of season"],answer:1,explanation:"Mowing is the foundation. Unlocks other services. Start there, build from it."}
];
